            XdrEnvelopeType.ENVELOPE_TYPE_AUTH,
            XdrEnvelopeType.ENVELOPE_TYPE_SCPVALUE,
            XdrEnvelopeType.ENVELOPE_TYPE_TX_FEE_BUMP,
            XdrEnvelopeType.ENVELOPE_TYPE_OP_ID,
